// Generate list of staff for interactive menu
const staff = $node['get_staff'].json;
const options = staff.map((s, i) => ({
  id: s.id.toString(),
  title: s.name
}));

return {
  staff_count: staff.length,
  staff_options: options,
  menu_message: `Great! Who would you like to book with?\n${options.map((s, i) => `${i+1}. ${s.title}`).join('\n')}`
};

// Get time slots for selected date
const date = $node['trigger'].json.selected_date;
const staff_id = $node['trigger'].json.selected_staff_id;

// Business hours: 9 AM to 5 PM (assuming 1 hour slots)
const slots = [];
for (let hour = 9; hour < 17; hour++) {
  slots.push({
    time: `${hour}:00`,
    label: `${hour > 12 ? hour - 12 : hour}:00 ${hour >= 12 ? 'PM' : 'AM'}`
  });
}

return {
  available_slots: slots,
  menu_message: `Available times on ${date}:\n${slots.map((s, i) => `${i+1}. ${s.label}`).join('\n')}`
};

return {
  success: true,
  appointment_created: true,
  message: `Appointment booked for ${$node['trigger'].json.selected_date} at ${$node['trigger'].json.selected_time}`
};
